const cfg = $input.item.json;

const CM_BASE = "https://clickmarket-backend-8scjo.ondigitalocean.app/api";
const SUPABASE_URL = cfg.supabase_url;
const SUPABASE_SERVICE_ROLE_KEY = cfg.supabase_service_role_key;
const PER_PAGE = 100;
const UPSERT_BATCH_SIZE = 500;

// ─── 1. Login — le token Bearer de ClickMarket n'est pas fiable dans la
// durée, on se reconnecte donc à chaque exécution du workflow.
const loginRes = await this.helpers.httpRequest({
  method: "POST",
  url: `${CM_BASE}/login`,
  headers: { "Content-Type": "application/json", Accept: "application/json" },
  body: {
    email: cfg.clickmarket_email,
    password: cfg.clickmarket_password,
  },
  json: true,
});

const token = loginRes.token;
if (!token) {
  throw new Error("ClickMarket login: aucun token reçu — vérifiez l'email/mot de passe dans le nœud 'Config'.");
}

// La réponse de /login contient déjà les marchés accessibles au compte.
const countries = loginRes.countries || [];

// ─── 2. Pour chaque marché, paginer /product-shipments jusqu'à la dernière page ───
const allRows = [];

for (const country of countries) {
  let page = 1;
  let lastPage = 1;

  do {
    const res = await this.helpers.httpRequest({
      method: "GET",
      url: `${CM_BASE}/product-shipments`,
      qs: { per_page: PER_PAGE, page },
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
        "X-Selected-Country": JSON.stringify({
          id: country.id,
          name: country.name,
          currency: country.currency,
        }),
      },
      json: true,
    });

    lastPage = res.pagination?.last_page ?? 1;

    for (const s of res.productShipments || []) {
      const countryName = s.warehouse?.country?.name ?? country.name;

      for (const item of s.shipment_items || []) {
        allRows.push({
          item_id: item.id,
          shipment_id: s.id,
          country: countryName,
          product_name: item.product?.name ?? "Inconnu",
          shipment_date: s.shipment_date ?? null,
          arrival_date: s.arrival_date ?? null,
          source_country: s.source_country ?? null,
          quantity_sent: item.quantity_sent ?? null,
          quantity_arrived: item.quantity_arrived ?? null,
          quantity_defected: item.quantity_defected ?? null,
          status: s.shipment_status ?? null,
        });
      }
    }

    page += 1;
  } while (page <= lastPage);
}

// ─── 3. Upsert en masse vers Supabase, par lots de 500 lignes ──────────────
// Dédup par item_id d'abord : la pagination peut chevaucher deux pages (un shipment modifié
// pendant le scan complet), et on ne veut pas que la même ligne apparaisse deux fois dans un
// même lot (Postgres refuse "ON CONFLICT DO UPDATE ... affect row a second time" dans ce cas —
// déjà observé en production sur les workflows de commandes). On garde la dernière occurrence.
const dedupedRows = Array.from(new Map(allRows.map((r) => [r.item_id, r])).values());

let upserted = 0;

for (let i = 0; i < dedupedRows.length; i += UPSERT_BATCH_SIZE) {
  const batch = dedupedRows.slice(i, i + UPSERT_BATCH_SIZE);

  await this.helpers.httpRequest({
    method: "POST",
    url: `${SUPABASE_URL}/rest/v1/clickmarket_shipments`,
    headers: {
      "Content-Type": "application/json",
      apikey: SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
      Prefer: "resolution=merge-duplicates,return=minimal",
    },
    body: batch,
    json: true,
  });

  upserted += batch.length;
}

return [
  {
    json: {
      synced_items: upserted,
      markets: countries.map((c) => c.name),
      finished_at: new Date().toISOString(),
    },
  },
];
